function pad(n) {
  return String(n).padStart(2, '0');
}

function formatDate(date) {
  return `${date.getFullYear()}-${pad(date.getMonth() + 1)}-${pad(date.getDate())}`;
}

function getWeekRange(date) {
  const dayOfWeek = date.getDay(); // domingo=0, lunes=1
  const diffToMonday = dayOfWeek === 0 ? -6 : 1 - dayOfWeek;

  const weekStart = new Date(date);
  weekStart.setDate(date.getDate() + diffToMonday);

  const weekEnd = new Date(weekStart);
  weekEnd.setDate(weekStart.getDate() + 6);

  return { weekStart, weekEnd };
}

function normalizeFileName(name) {
  return String(name || '')
    .trim()
    .replace(/\s+/g, ' ')
    .toLowerCase();
}

function validateAndExtractDate(file) {
  const name = file.name || '';
  const mimeType = file.mimeType || '';

  const isPdf =
    mimeType === 'application/pdf' ||
    name.toLowerCase().endsWith('.pdf');

  if (!isPdf) {
    return {
      valid: false,
      reason: 'El archivo no es PDF'
    };
  }

  if (!name.toLowerCase().endsWith('.pdf')) {
    return {
      valid: false,
      reason: 'El archivo tiene MIME type de PDF, pero el nombre no termina en .pdf'
    };
  }

  // Formato esperado:
  // POD ALT10996 - 51526-8852LB.pdf
  // POD ALT11014 -  51626-8858LB.pdf
  const fullPattern = /^\s*POD\s+CAR(\d+)\s*-\s*(\d{5,6})-(\d+)([A-Z]{2})\.pdf\s*$/i;
  const match = name.match(fullPattern);

  if (!match) {
    return {
      valid: false,
      reason: 'El nombre no cumple el formato esperado: POD CAR##### - MMDDYY-####LB.pdf'
    };
  }

  const altNumber = match[1];
  const rawDate = match[2];
  const loadNumber = match[3];
  const suffix = match[4].toUpperCase();

  let month;
  let day;
  let year;

  if (rawDate.length === 5) {
    // Ejemplo: 51526 = 5/15/26
    month = Number(rawDate.slice(0, 1));
    day = Number(rawDate.slice(1, 3));
    year = Number(rawDate.slice(3, 5));
  } else {
    // Ejemplo: 101526 = 10/15/26
    month = Number(rawDate.slice(0, 2));
    day = Number(rawDate.slice(2, 4));
    year = Number(rawDate.slice(4, 6));
  }

  if (!Number.isInteger(month) || month < 1 || month > 12) {
    return {
      valid: false,
      reason: `Mes inválido en la fecha: ${rawDate}`,
      rawDate,
      altNumber,
      loadNumber,
      suffix
    };
  }

  if (!Number.isInteger(day) || day < 1 || day > 31) {
    return {
      valid: false,
      reason: `Día inválido en la fecha: ${rawDate}`,
      rawDate,
      altNumber,
      loadNumber,
      suffix
    };
  }

  year = 2000 + year;

  const date = new Date(year, month - 1, day);

  // Validación estricta para evitar conversiones automáticas de JS.
  // Ejemplo: 04/31/2026 no debe convertirse a 05/01/2026.
  if (
    isNaN(date.getTime()) ||
    date.getFullYear() !== year ||
    date.getMonth() !== month - 1 ||
    date.getDate() !== day
  ) {
    return {
      valid: false,
      reason: `Fecha inválida o inexistente: ${rawDate}`,
      rawDate,
      altNumber,
      loadNumber,
      suffix
    };
  }

  return {
    valid: true,
    rawDate,
    date,
    altNumber,
    loadNumber,
    suffix
  };
}

// Soporta dos estructuras:
// 1. Directo desde Get All PDFs: { files: [...] }
// 2. Items separados: cada item es un archivo
const inputItems = $input.all();

let files = [];

if (inputItems.length === 1 && Array.isArray(inputItems[0].json.files)) {
  files = inputItems[0].json.files;
} else {
  files = inputItems.map(item => item.json);
}

const groups = {};
const invalidFiles = [];
const seenFileNames = {};
const seenBusinessKeys = {};

for (const file of files) {
  const validation = validateAndExtractDate(file);

  if (!validation.valid) {
    invalidFiles.push({
      id: file.id || null,
      name: file.name || null,
      mimeType: file.mimeType || null,
      webViewLink: file.webViewLink || null,
      reason: validation.reason,
      rawDate: validation.rawDate || null
    });

    continue;
  }

  const normalizedName = normalizeFileName(file.name);

  const businessKey = [
    validation.altNumber,
    validation.rawDate,
    validation.loadNumber,
    validation.suffix
  ].join('-');

  if (seenFileNames[normalizedName]) {
    invalidFiles.push({
      id: file.id || null,
      name: file.name || null,
      mimeType: file.mimeType || null,
      webViewLink: file.webViewLink || null,
      reason: 'Archivo duplicado por nombre. Ya existe otro archivo con el mismo nombre.',
      duplicateType: 'file_name',
      duplicateOfId: seenFileNames[normalizedName].id,
      duplicateOfName: seenFileNames[normalizedName].name,
      rawDate: validation.rawDate || null,
      altNumber: validation.altNumber,
      loadNumber: validation.loadNumber,
      suffix: validation.suffix
    });

    continue;
  }

  if (seenBusinessKeys[businessKey]) {
    invalidFiles.push({
      id: file.id || null,
      name: file.name || null,
      mimeType: file.mimeType || null,
      webViewLink: file.webViewLink || null,
      reason: 'Archivo duplicado por combinación CAR + fecha + load + sufijo.',
      duplicateType: 'business_key',
      duplicateOfId: seenBusinessKeys[businessKey].id,
      duplicateOfName: seenBusinessKeys[businessKey].name,
      rawDate: validation.rawDate || null,
      altNumber: validation.altNumber,
      loadNumber: validation.loadNumber,
      suffix: validation.suffix
    });

    continue;
  }

  seenFileNames[normalizedName] = {
    id: file.id || null,
    name: file.name || null
  };

  seenBusinessKeys[businessKey] = {
    id: file.id || null,
    name: file.name || null
  };

  const { weekStart, weekEnd } = getWeekRange(validation.date);

  const fileDate = formatDate(validation.date);
  const weekStartText = formatDate(weekStart);
  const weekEndText = formatDate(weekEnd);
  const weekGroup = `${weekStartText}_to_${weekEndText}`;

  if (!groups[weekGroup]) {
    groups[weekGroup] = {
      outputType: 'week_group',
      weekGroup,
      weekStart: weekStartText,
      weekEnd: weekEndText,
      totalFiles: 0,
      files: []
    };
  }

  groups[weekGroup].files.push({
    ...file,
    altNumber: validation.altNumber,
    loadNumber: validation.loadNumber,
    suffix: validation.suffix,
    rawDate: validation.rawDate,
    fileDate,
    weekGroup,
    weekStart: weekStartText,
    weekEnd: weekEndText
  });
}

for (const group of Object.values(groups)) {
  group.files.sort((a, b) => {
    if (a.fileDate !== b.fileDate) {
      return a.fileDate.localeCompare(b.fileDate);
    }

    return a.name.localeCompare(b.name);
  });

  group.totalFiles = group.files.length;
}

const totalValidFiles = Object.values(groups).reduce((sum, group) => {
  return sum + group.totalFiles;
}, 0);

const output = Object.values(groups)
  .sort((a, b) => a.weekStart.localeCompare(b.weekStart))
  .map(group => ({
    json: group
  }));

output.push({
  json: {
    outputType: 'validation_report',
    totalFilesDetected: files.length,
    totalValidFiles,
    totalInvalidFiles: invalidFiles.length,
    totalDuplicateFiles: invalidFiles.filter(file =>
      file.duplicateType === 'file_name' ||
      file.duplicateType === 'business_key'
    ).length,
    invalidFiles
  }
});

return output;

function pad(n) {
  return String(n).padStart(2, '0');
}

function formatDate(date) {
  return `${date.getFullYear()}-${pad(date.getMonth() + 1)}-${pad(date.getDate())}`;
}

function parseRawDate(rawDate) {
  let month;
  let day;
  let year;

  if (!/^\d{5,6}$/.test(rawDate)) {
    return {
      valid: false,
      reason: `La fecha del PO no tiene 5 o 6 dígitos: ${rawDate}`
    };
  }

  if (rawDate.length === 5) {
    // Ejemplo: 51526 = 5/15/26
    month = Number(rawDate.slice(0, 1));
    day = Number(rawDate.slice(1, 3));
    year = Number(rawDate.slice(3, 5));
  } else {
    // Ejemplo: 101526 = 10/15/26
    month = Number(rawDate.slice(0, 2));
    day = Number(rawDate.slice(2, 4));
    year = Number(rawDate.slice(4, 6));
  }

  if (!Number.isInteger(month) || month < 1 || month > 12) {
    return {
      valid: false,
      reason: `Mes inválido en la fecha del PO: ${rawDate}`
    };
  }

  if (!Number.isInteger(day) || day < 1 || day > 31) {
    return {
      valid: false,
      reason: `Día inválido en la fecha del PO: ${rawDate}`
    };
  }

  year = 2000 + year;

  const date = new Date(year, month - 1, day);

  if (
    isNaN(date.getTime()) ||
    date.getFullYear() !== year ||
    date.getMonth() !== month - 1 ||
    date.getDate() !== day
  ) {
    return {
      valid: false,
      reason: `Fecha del PO inválida o inexistente: ${rawDate}`
    };
  }

  return {
    valid: true,
    date,
    month,
    day,
    year
  };
}

function normalizeText(value) {
  return String(value || '').trim().replace(/\s+/g, ' ');
}

function normalizeMoney(value) {
  return String(value || '').trim();
}

function parsePO(poValue) {
  const po = normalizeText(poValue);

  if (!po) {
    return {
      valid: false,
      reason: 'La columna PO está vacía'
    };
  }

  // Formato esperado en Sheet:
  // ALT10996 - 51526-8852LB
  // También tolera:
  // POD ALT10996 - 51526-8852LB.pdf
  const pattern = /^\s*(?:POD\s+)?CAR(\d+)\s*-\s*(\d{5,6})-(\d+)\s*([A-Z]{2})\s*(?:\.pdf)?\s*$/i;
  const match = po.match(pattern);

  if (!match) {
    return {
      valid: false,
      reason: 'El PO no cumple el formato esperado: CAR##### - MMDDYY-####LB',
      po
    };
  }

  const altNumber = match[1];
  const rawDate = match[2];
  const loadNumber = match[3];
  const suffix = match[4].toUpperCase();

  // Esta validación se mantiene porque la fecha forma parte de la clave del PO/PDF.
  // No se usa para validar DATE del Sheet ni para calcular la semana de facturación.
  const parsedDate = parseRawDate(rawDate);

  if (!parsedDate.valid) {
    return {
      valid: false,
      reason: parsedDate.reason,
      po,
      rawDate,
      altNumber,
      loadNumber,
      suffix
    };
  }

  const poKey = [
    altNumber,
    rawDate,
    loadNumber,
    suffix
  ].join('-');

  const normalizedPO = `CAR${altNumber} - ${rawDate}-${loadNumber}${suffix}`;
  const expectedPdfName = `POD CAR${altNumber} - ${rawDate}-${loadNumber}${suffix}.pdf`;

  return {
    valid: true,
    po,
    normalizedPO,
    expectedPdfName,
    poKey,
    altNumber,
    rawDate,
    loadNumber,
    suffix,
    dateFromPO: parsedDate.date
  };
}

const inputItems = $input.all();

const readyRows = [];
const invalidRows = [];

// DATE del Sheet se conserva solo como dato informativo.
// No se parsea, no se valida, no bloquea y no calcula semana.
for (let index = 0; index < inputItems.length; index++) {
  const row = inputItems[index].json;

  const poValue = row.PO;
  const sheetDateInformative = row.DATE ?? null;

  const parsedPO = parsePO(poValue);

  if (!parsedPO.valid) {
    invalidRows.push({
      rowIndex: index,
      PO: poValue || null,
      DATE: sheetDateInformative,
      sheetDateInformative,
      reason: parsedPO.reason,
      originalRow: row
    });

    continue;
  }

  const poDateText = formatDate(parsedPO.dateFromPO);

  const readyRow = {
    rowIndex: index,

    // Campos normalizados para cruzar contra PDF.
    poKey: parsedPO.poKey,
    normalizedPO: parsedPO.normalizedPO,
    expectedPdfName: parsedPO.expectedPdfName,

    altNumber: parsedPO.altNumber,
    rawDate: parsedPO.rawDate,
    loadNumber: parsedPO.loadNumber,
    suffix: parsedPO.suffix,

    // Fecha del PO solo como referencia de la clave.
    // La semana oficial se asigna después, en Cruzar Facturas, usando el PDF encontrado.
    dateFromPO: poDateText,
    poDateInformative: poDateText,

    // DATE del Sheet queda solo para trazabilidad.
    DATE: sheetDateInformative,
    sheetDateInformative,

    // Estos campos se llenan después desde el PDF.
    date: null,
    dateFromPdf: null,
    fileDate: null,
    weekGroup: null,
    weekStart: null,
    weekEnd: null,

    // Campos neutrales para compatibilidad; ya no dependen de DATE del Sheet.
    hasDateMismatch: false,
    dateMismatchWarning: null,
    dateRelationStatus: 'NOT_EVALUATED_SHEET_DATE_IGNORED',
    dateRelationFacturable: true,
    dateRelationMessage: 'DATE del Sheet conservado solo como dato informativo; no se valida ni bloquea.',
    dateRelationPoWeekGroup: null,
    dateRelationSheetWeekGroup: null,

    // Campos del Sheet que se usan para la factura.
    TRUCK: row.TRUCK || null,
    TRIP: row['TRIP´#'] || row['TRIP #'] || row.TRIP || null,
    DRIVER: row.DRIVER || null,
    BROKER: row.BROKER || null,
    PO: row.PO || null,
    PICK_UP: row['PICK UP'] || null,
    DROP: row.DROP || null,
    BILL: row.BILL || null,
    RC: row.RC || null,
    DI: row.DI || null,
    POD: row.POD || null,
    AMOUNT: normalizeMoney(row.AMOUNT),
    RATE: normalizeMoney(row.Rate || row.RATE),
    factura_hecha: row['factura hecha'] || null,

    originalRow: row
  };

  readyRows.push(readyRow);
}

readyRows.sort((a, b) => {
  return a.normalizedPO.localeCompare(b.normalizedPO);
});

return [
  {
    json: {
      outputType: 'ready_rows_package',
      maxPerInvoice: 12,

      totalRowsDetected: inputItems.length,
      totalReadyRows: readyRows.length,
      totalInvalidRows: invalidRows.length,

      // Se conservan en cero por compatibilidad, pero ya no se calculan desde DATE del Sheet.
      totalRowsWithDateMismatch: 0,
      totalRowsWithDateRelationBlocked: 0,
      totalWeeks: 0,

      readyRows,
      rowsByWeek: [],
      invalidRows,
      dateMismatchRows: [],
      dateRelationBlockedRows: [],

      dateSheetPolicy: {
        mode: 'informative_only',
        validates: false,
        blocks: false,
        calculatesWeek: false
      }
    }
  }
];

const MAX_PER_INVOICE = 12;

function chunkArray(array, size) {
  const chunks = [];

  for (let i = 0; i < array.length; i += size) {
    chunks.push(array.slice(i, i + size));
  }

  return chunks;
}

function makePdfKey(file) {
  return [
    file.altNumber,
    file.rawDate,
    file.loadNumber,
    file.suffix
  ].join('-');
}

function parseAmount(value) {
  if (value === undefined || value === null || value === '') {
    return 0;
  }

  const cleaned = String(value)
    .replace(/\$/g, '')
    .replace(/,/g, '')
    .replace(/\s/g, '')
    .trim();

  const number = Number(cleaned);

  return Number.isFinite(number) ? number : 0;
}

function sortRows(a, b) {
  const aDate = a.dateFromPdf || a.fileDate || a.matchedFile?.fileDate || '';
  const bDate = b.dateFromPdf || b.fileDate || b.matchedFile?.fileDate || '';

  if (aDate !== bDate) {
    return String(aDate).localeCompare(String(bDate));
  }

  return String(a.normalizedPO || '').localeCompare(String(b.normalizedPO || ''));
}

function getPdfWeekKey(file) {
  return file?.sourceWeekGroup || file?.weekGroup || null;
}

function getPdfWeekStart(file) {
  return file?.sourceWeekStart || file?.weekStart || null;
}

function getPdfWeekEnd(file) {
  return file?.sourceWeekEnd || file?.weekEnd || null;
}

// Este nombre debe coincidir EXACTAMENTE con tu nodo anterior.
const preparedPackage = $('Preparar facturas listas').first().json;

const readyRows = preparedPackage.readyRows || [];
const invalidRowsFromPrepare = preparedPackage.invalidRows || [];

// Input directo de este nodo: salida de "Agrupar por semana".
const inputItems = $input.all().map(item => item.json);

const pdfWeekGroups = inputItems.filter(item => item.outputType === 'week_group');
const pdfValidationReports = inputItems.filter(item => item.outputType === 'validation_report');

const pdfValidationReport = pdfValidationReports[0] || {
  totalFilesDetected: 0,
  totalValidFiles: 0,
  totalInvalidFiles: 0,
  totalDuplicateFiles: 0,
  invalidFiles: []
};

const pdfByKey = {};
const allValidPdfFiles = [];

for (const group of pdfWeekGroups) {
  const files = group.files || [];

  for (const file of files) {
    const pdfKey = makePdfKey(file);

    const enrichedFile = {
      ...file,
      pdfKey,
      sourceWeekGroup: group.weekGroup,
      sourceWeekStart: group.weekStart,
      sourceWeekEnd: group.weekEnd
    };

    allValidPdfFiles.push(enrichedFile);

    if (!pdfByKey[pdfKey]) {
      pdfByKey[pdfKey] = [];
    }

    pdfByKey[pdfKey].push(enrichedFile);
  }
}

const rowsByWeek = {};
const matchedPdfKeys = {};
const seenSheetKeys = {};

for (const row of readyRows) {
  const rowKey = row.poKey;
  const pdfMatches = pdfByKey[rowKey] || [];
  const referenceFile = pdfMatches[0] || null;

  let matchStatus = 'matched';
  let matchReason = null;
  let matchedFile = null;

  if (seenSheetKeys[rowKey]) {
    matchStatus = 'sheet_duplicate';
    matchReason = 'PO duplicado dentro de las filas listas del Sheet';
  } else {
    seenSheetKeys[rowKey] = {
      rowIndex: row.rowIndex,
      PO: row.PO,
      normalizedPO: row.normalizedPO
    };

    if (pdfMatches.length === 0) {
      matchStatus = 'missing_pdf';
      matchReason = 'No se encontró PDF correspondiente en Drive';
    } else if (pdfMatches.length > 1) {
      matchStatus = 'duplicate_pdf';
      matchReason = 'Se encontró más de un PDF válido con la misma clave';
    } else {
      matchedFile = pdfMatches[0];
      matchedPdfKeys[rowKey] = true;
    }
  }

  const effectiveFile = matchedFile || referenceFile;
  const pdfWeekGroup = getPdfWeekKey(effectiveFile);
  const pdfWeekStart = getPdfWeekStart(effectiveFile);
  const pdfWeekEnd = getPdfWeekEnd(effectiveFile);
  const pdfFileDate = effectiveFile?.fileDate || null;

  const enrichedRow = {
    ...row,

    matchStatus,
    matchReason,
    matchedFile,

    // Fecha y semana oficiales: salen exclusivamente del PDF encontrado.
    date: pdfFileDate,
    dateFromPdf: pdfFileDate,
    fileDate: pdfFileDate,
    weekGroup: pdfWeekGroup,
    weekStart: pdfWeekStart,
    weekEnd: pdfWeekEnd,

    // DATE del Sheet se mantiene únicamente como dato informativo.
    sheetDateInformative: row.sheetDateInformative ?? row.DATE ?? null,

    // Compatibilidad sin bloqueo por DATE.
    hasDateMismatch: false,
    dateMismatchWarning: null,
    dateRelationStatus: 'NOT_EVALUATED_SHEET_DATE_IGNORED',
    dateRelationFacturable: true,
    dateRelationMessage: 'DATE del Sheet conservado solo como dato informativo; no se valida ni bloquea.',
    dateRelationPoWeekGroup: null,
    dateRelationSheetWeekGroup: null
  };

  // Si no hay PDF, no existe semana oficial calculable desde filename.
  // Se agrupa en una llave de diagnóstico, sin inventar semana desde DATE del Sheet ni desde PO.
  const groupKey = pdfWeekGroup || 'WITHOUT_MATCHED_PDF';
  const groupStart = pdfWeekStart || null;
  const groupEnd = pdfWeekEnd || null;

  if (!rowsByWeek[groupKey]) {
    rowsByWeek[groupKey] = {
      weekGroup: groupKey,
      weekStart: groupStart,
      weekEnd: groupEnd,
      rows: []
    };
  }

  rowsByWeek[groupKey].rows.push(enrichedRow);
}

for (const group of Object.values(rowsByWeek)) {
  group.rows.sort(sortRows);
}

const output = [];
const readyInvoiceGroups = [];
const notReadyInvoiceGroups = [];

const sortedWeekGroups = Object.values(rowsByWeek)
  .sort((a, b) => {
    const aStart = a.weekStart || '9999-99-99';
    const bStart = b.weekStart || '9999-99-99';

    if (aStart !== bStart) {
      return aStart.localeCompare(bStart);
    }

    return String(a.weekGroup).localeCompare(String(b.weekGroup));
  });

for (const weekGroup of sortedWeekGroups) {
  const chunks = chunkArray(weekGroup.rows, MAX_PER_INVOICE);
  const totalParts = chunks.length;

  chunks.forEach((chunk, index) => {
    const part = index + 1;
    const invoiceGroupKey = `${weekGroup.weekGroup}_part_${part}`;

    const matchedRows = chunk.filter(row => row.matchStatus === 'matched');
    const problemRows = chunk.filter(row => row.matchStatus !== 'matched');

    const files = matchedRows
      .map(row => row.matchedFile)
      .filter(Boolean);

    const totalAmount = matchedRows.reduce((sum, row) => {
      return sum + parseAmount(row.AMOUNT);
    }, 0);

    const baseGroup = {
      invoiceGroupKey,
      weekGroup: weekGroup.weekGroup,
      weekStart: weekGroup.weekStart,
      weekEnd: weekGroup.weekEnd,
      part,
      totalParts,
      maxPerInvoice: MAX_PER_INVOICE,

      totalRows: chunk.length,
      totalMatchedRows: matchedRows.length,
      totalProblemRows: problemRows.length,
      totalFiles: files.length,
      totalAmount,

      rows: chunk,
      matchedRows,
      problemRows,
      files,

      weekSource: weekGroup.weekGroup === 'WITHOUT_MATCHED_PDF'
        ? 'no_pdf_match_available'
        : 'pdf_filename'
    };

    if (problemRows.length === 0) {
      const readyGroup = {
        outputType: 'invoice_ready_group',
        ...baseGroup
      };

      readyInvoiceGroups.push(readyGroup);
      output.push({ json: readyGroup });
    } else {
      const notReadyGroup = {
        outputType: 'invoice_not_ready_group',
        ...baseGroup,
        missingRows: problemRows.filter(row => row.matchStatus === 'missing_pdf'),
        duplicateSheetRows: problemRows.filter(row => row.matchStatus === 'sheet_duplicate'),
        duplicatePdfRows: problemRows.filter(row => row.matchStatus === 'duplicate_pdf')
      };

      notReadyInvoiceGroups.push(notReadyGroup);
      output.push({ json: notReadyGroup });
    }
  });
}

const readySheetKeys = {};
for (const row of readyRows) {
  readySheetKeys[row.poKey] = true;
}

const ignoredValidPdfFiles = allValidPdfFiles.filter(file => {
  return !readySheetKeys[file.pdfKey];
});

const crosscheckReport = {
