  }
};

output.push({
  json: crosscheckReport
});

return output;

function normalizeText(value) {
  return String(value || '').trim().replace(/\s+/g, ' ');
}

function analyzeAmount(value) {
  const originalValue = value;

  if (value === undefined || value === null || String(value).trim() === '') {
    return {
      valid: false,
      amount: null,
      reason: 'El campo AMOUNT está vacío',
      originalValue
    };
  }

  const cleaned = String(value)
    .replace(/\$/g, '')
    .replace(/,/g, '')
    .replace(/\s/g, '')
    .trim();

  if (cleaned === '') {
    return {
      valid: false,
      amount: null,
      reason: 'El campo AMOUNT no contiene un valor numérico',
      originalValue
    };
  }

  const number = Number(cleaned);

  if (!Number.isFinite(number)) {
    return {
      valid: false,
      amount: null,
      reason: `El campo AMOUNT no es numérico: ${value}`,
      originalValue
    };
  }

  return {
    valid: true,
    amount: number,
    reason: null,
    originalValue
  };
}

function formatMoney(value) {
  const number = Number(value);

  if (!Number.isFinite(number)) {
    return '';
  }

  return '$' + number.toLocaleString('de-DE', {
    minimumFractionDigits: 2,
    maximumFractionDigits: 2
  });
}

function formatDateUS(value) {
  if (!value) {
    return '';
  }

  const text = String(value).trim();

  const isoMatch = text.match(/^(\d{4})-(\d{2})-(\d{2})$/);

  if (isoMatch) {
    const year = isoMatch[1];
    const month = isoMatch[2];
    const day = isoMatch[3];

    return `${month}/${day}/${year}`;
  }

  const slashMatch = text.match(/^(\d{1,2})\/(\d{1,2})\/(\d{2,4})$/);

  if (slashMatch) {
    const month = String(slashMatch[1]).padStart(2, '0');
    const day = String(slashMatch[2]).padStart(2, '0');
    let year = slashMatch[3];

    if (year.length === 2) {
      year = `20${year}`;
    }

    return `${month}/${day}/${year}`;
  }

  return text;
}

// NUEVA FUNCIÓN PARA FORMATO DE FECHA DE FACTURA:
// 2026-05-16 => 16 May 2026
// 05/16/2026 => 16 May 2026
function formatDateInvoiceLong(value) {
  if (!value) {
    return '';
  }

  let year;
  let month;
  let day;

  if (value instanceof Date) {
    if (isNaN(value.getTime())) {
      return '';
    }

    year = value.getFullYear();
    month = value.getMonth() + 1;
    day = value.getDate();
  } else {
    const text = String(value).trim();

    const isoMatch = text.match(/^(\d{4})-(\d{1,2})-(\d{1,2})$/);

    if (isoMatch) {
      year = Number(isoMatch[1]);
      month = Number(isoMatch[2]);
      day = Number(isoMatch[3]);
    } else {
      const slashMatch = text.match(/^(\d{1,2})\/(\d{1,2})\/(\d{2,4})$/);

      if (slashMatch) {
        month = Number(slashMatch[1]);
        day = Number(slashMatch[2]);
        year = Number(slashMatch[3]);

        if (year < 100) {
          year = 2000 + year;
        }
      } else {
        return text;
      }
    }
  }

  const date = new Date(year, month - 1, day);

  if (
    isNaN(date.getTime()) ||
    date.getFullYear() !== year ||
    date.getMonth() !== month - 1 ||
    date.getDate() !== day
  ) {
    return '';
  }

  const months = [
    'Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun',
    'Jul', 'Aug', 'Sep', 'Oct', 'Nov', 'Dec'
  ];

  return `${day} ${months[month - 1]} ${year}`;
}

function pad(n) {
  return String(n).padStart(2, '0');
}

function formatDateISO(date) {
  return `${date.getFullYear()}-${pad(date.getMonth() + 1)}-${pad(date.getDate())}`;
}

function parseISODateOnly(value) {
  if (!value) {
    return null;
  }

  const text = String(value).trim();
  const match = text.match(/^(\d{4})-(\d{1,2})-(\d{1,2})$/);

  if (!match) {
    return null;
  }

  const year = Number(match[1]);
  const month = Number(match[2]);
  const day = Number(match[3]);
  const date = new Date(year, month - 1, day);

  if (
    isNaN(date.getTime()) ||
    date.getFullYear() !== year ||
    date.getMonth() !== month - 1 ||
    date.getDate() !== day
  ) {
    return null;
  }

  return date;
}

function getSaturdayFromWeekStart(weekStartText) {
  const weekStart = parseISODateOnly(weekStartText);

  if (!weekStart) {
    return null;
  }

  const saturday = new Date(weekStart);
  saturday.setDate(weekStart.getDate() + 5);

  return saturday;
}

function getInvoiceDateFromBillingWeek(invoiceGroup, files, rows, invoiceBaseRow) {
  // La fecha de factura sale de la semana calculada desde el nombre del PDF.
  // Prioridad: metadata del PDF > metadata del grupo > metadata de la fila enriquecida.
  const invoiceWeekStart =
    files?.[0]?.sourceWeekStart ||
    files?.[0]?.weekStart ||
    invoiceGroup.weekStart ||
    rows?.[0]?.weekStart ||
    null;

  const saturday = getSaturdayFromWeekStart(invoiceWeekStart);

  if (saturday) {
    return formatDateInvoiceLong(formatDateISO(saturday));
  }

  // Fallback defensivo: usar fecha del PDF si existe.
  const pdfDate =
    files?.[0]?.fileDate ||
    rows?.[0]?.dateFromPdf ||
    rows?.[0]?.fileDate ||
    rows?.[0]?.matchedFile?.fileDate ||
    null;

  return formatDateInvoiceLong(pdfDate);
}

function parseDateForSort(value) {
  if (!value) {
    return Number.POSITIVE_INFINITY;
  }

  const text = String(value).trim();

  const isoMatch = text.match(/^(\d{4})-(\d{1,2})-(\d{1,2})$/);

  if (isoMatch) {
    const year = Number(isoMatch[1]);
    const month = Number(isoMatch[2]);
    const day = Number(isoMatch[3]);
    const date = new Date(year, month - 1, day);

    return Number.isFinite(date.getTime()) ? date.getTime() : Number.POSITIVE_INFINITY;
  }

  const slashMatch = text.match(/^(\d{1,2})\/(\d{1,2})\/(\d{2,4})$/);

  if (slashMatch) {
    const month = Number(slashMatch[1]);
    const day = Number(slashMatch[2]);
    let year = Number(slashMatch[3]);

    if (year < 100) {
      year = 2000 + year;
    }

    const date = new Date(year, month - 1, day);

    return Number.isFinite(date.getTime()) ? date.getTime() : Number.POSITIVE_INFINITY;
  }

  return Number.POSITIVE_INFINITY;
}

function getInvoiceBaseRow(rows) {
  if (!Array.isArray(rows) || rows.length === 0) {
    return null;
  }

  return rows.reduce((selectedRow, currentRow) => {
    const selectedDate = parseDateForSort(
      selectedRow.dateFromPdf || selectedRow.fileDate || selectedRow.matchedFile?.fileDate
    );

    const currentDate = parseDateForSort(
      currentRow.dateFromPdf || currentRow.fileDate || currentRow.matchedFile?.fileDate
    );

    if (currentDate < selectedDate) {
      return currentRow;
    }

    if (currentDate === selectedDate) {
      const selectedIndex = Number(selectedRow.rowIndex ?? Number.POSITIVE_INFINITY);
      const currentIndex = Number(currentRow.rowIndex ?? Number.POSITIVE_INFINITY);

      if (currentIndex < selectedIndex) {
        return currentRow;
      }
    }

    return selectedRow;
  }, rows[0]);
}

function countDestinations(dropValue) {
  const drop = normalizeText(dropValue);

  if (!drop) {
    return 0;
  }

  const destinations = drop
    .split(/\s*(?:,|;|\||\/|\+|&)\s*/)
    .map(destination => destination.trim())
    .filter(Boolean);

  return destinations.length || 1;
}

function extractAltFromRow(row) {
  if (row.altNumber) {
    return `CAR${row.altNumber}`;
  }

  const po = normalizeText(row.PO);
  const match = po.match(/CAR\d+/i);

  if (match) {
    return match[0].toUpperCase();
  }

  return 'ALT_UNKNOWN';
}

function buildPoText(row) {
  if (row.rawDate && row.loadNumber && row.suffix) {
    return `${row.rawDate}-${row.loadNumber}${row.suffix}`;
  }

  const po = normalizeText(row.PO);

  if (!po) {
    return '';
  }

  return po.replace(/^\s*CAR\d+\s*-\s*/i, '').trim();
}

function buildTripText(row) {
  const drop = normalizeText(row.DROP);
  const alt = extractAltFromRow(row);

  if (!drop && alt === 'ALT_UNKNOWN') {
    return '';
  }

  if (!drop) {
    return `(${alt}) [HUB CITY]`;
  }

  if (alt === 'ALT_UNKNOWN') {
    return `${drop} [HUB CITY]`;
  }

  return `${drop} (${alt}) [HUB CITY]`;
}

function addReplacement(replacements, replacementArray, key, value) {
  const safeValue = value === undefined || value === null ? '' : String(value);

  replacements[key] = safeValue;

  replacementArray.push({
    placeholder: `{{${key}}}`,
    value: safeValue
  });
}

function addLinePlaceholderVariants(replacements, replacementArray, base, index, value) {
  const safeValue = value === undefined || value === null ? '' : String(value);
  const twoDigit = String(index).padStart(2, '0');

  addReplacement(replacements, replacementArray, `${base}${twoDigit}`, safeValue);
  addReplacement(replacements, replacementArray, `${base}${index}`, safeValue);
  addReplacement(replacements, replacementArray, `${base} ${index}`, safeValue);
}

function getPdfDateFromRow(row) {
  return (
    row.dateFromPdf ||
    row.fileDate ||
    row.date ||
    row.matchedFile?.fileDate ||
    null
  );
}

function getSheetDateInformative(row) {
  return row.sheetDateInformative ?? row.DATE ?? null;
}

function buildRowsToMark(rows, status, reason) {
  return rows.map(row => ({
    rowIndex: row.rowIndex,
    PO: row.PO || null,
    DATE: getSheetDateInformative(row),
    sheetDateInformative: getSheetDateInformative(row),
    status,
    reason,
    originalRow: row.originalRow || row
  }));
}

const invoiceGroup = $json;

if (invoiceGroup.outputType !== 'invoice_ready_group') {
