      sub2Formatted: unit2 > 0 ? formatMoney(sub2) : '',
      rate1Formatted: unit1 > 0 ? formatMoney(rate1) : '',
      rate2Formatted: unit2 > 0 ? formatMoney(rate2) : '',
      totalFormatted: formatMoney(total),

      totalRows: rows.length,
      totalFiles: files.length,

      lineItems,
      singleDestinationRows,
      multiDestinationRows,

      rowsToMark,
      rows,
      files,

      replacements,
      replacementArray
    }
  }
];

const invoice = $json;

const lineItems = Array.isArray(invoice.lineItems) ? invoice.lineItems : [];

const output = [];

for (const line of lineItems) {
  const file = line.matchedFile;

  if (!file?.id) {
    continue;
  }

  output.push({
    json: {
      invoiceGroupKey: invoice.invoiceGroupKey,
      invoiceNumber: invoice.invoiceNumber,
      invoiceFilename: invoice.filename,

      sourceType: 'related_pdf',
      mergeOrder: line.lineNumber,

      fileId: file.id,
      fileName: file.name,

      lineNumber: line.lineNumber,
      PO: line.PO_FULL || line.PO,
      TRIP: line.TRIP,

      // DATE operativo viene del PDF. DATE del Sheet queda solo como metadata informativa.
      DATE: line.DATE,
      pdfDate: line.pdfDate,
      sheetDateInformative: line.sheetDateInformative,
    }
  });
}

return output;

const invoice = $('Prep Dat Fact').item.json;
const upload = $json;

const rowsToMark = Array.isArray(invoice.rowsToMark)
  ? invoice.rowsToMark
  : [];

const finalFileId = upload.id || upload.fileId || null;
const finalFileName = upload.name || invoice.filename || null;
const finalFileUrl =
  upload.webViewLink ||
  upload.webContentLink ||
  (finalFileId ? `https://drive.google.com/file/d/${finalFileId}/view` : null);

return rowsToMark.map((row) => {
  const originalRow = row.originalRow || {};

  return {
    json: {
      // Este PO debe coincidir con el PO de la hoja.
      // Uso primero originalRow.PO porque conserva espacios dobles si existieran.
      lookupPO: originalRow.PO || row.PO,

      // DATE del Sheet se conserva solo como dato informativo.
      DATE: originalRow.DATE || row.sheetDateInformative || row.DATE,
      sheetDateInformative: originalRow.DATE || row.sheetDateInformative || row.DATE,
      BROKER: originalRow.BROKER || null,
      PO: originalRow.PO || row.PO,

      // Campo principal a actualizar
      factura_hecha: row.status || 'Si',

      // Metadata útil para control interno
      invoiceNumber: invoice.invoiceNumber,
      invoiceFilename: invoice.filename,
      invoiceGroupKey: invoice.invoiceGroupKey,
      finalFileId,
      finalFileName,
      finalFileUrl,

      updateReason: row.reason || 'Factura generada correctamente'
    }
  };
});
